package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithHeader() throws NoSuchMethodException, SecurityException, IllegalAccessException, IllegalArgumentException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        String[] header = {"Header1", "Header2"};

        // When
        Method method = CSVFormat.class.getDeclaredMethod("withHeader", String[].class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(csvFormat, new Object[] { header });

        // Then
        assertNotNull(result);
        assertArrayEquals(header, result.getHeader());
    }
}
